  "objectives": [],
  "questionProse": [
    "`COUNT(column_name)` 在 SQL 中的作用是什么？"
  ],
  "hintsProse": [],
  "explanationProse": [
    "`COUNT(column_name)` 统计指定列中非 NULL 值的数量。若想计数所有行（包括 NULL），请使用 `COUNT(*)`。\n\n您也可以使用 `COALESCE` 将 NULL 转换为非 NULL 值，例如：`COUNT(COALESCE(column_name, 0))`。"
  ]
}
